// HCPA - Residência Médica 2022 (Acesso Direto e Prova de Autoavaliação)
export const HCPA_2022_QUESTIONS: any[] = [
  { id: "hcpa_2022_001", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido com 36 semanas de idade gestacional, filho de mãe internada em CTI-COVID, submetida a cesariana devido às condições clínicas de deterioração, sem outros fatores de risco perinatais, terá alta hospitalar com o pai e a avó, ao completar 84 horas de vida. Neste período pandêmico, recomenda-se que a triagem metabólica neonatal (teste do pezinho) seja realizada", options: ["no momento do nascimento, na Maternidade.", "no momento da alta, na Maternidade.", "do terceiro ao sétimo dia de vida, na UBS.", "até o trigésimo dia de vida, na UBS."], correctIndex: 1 },
  { id: "hcpa_2022_002", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido com 37 semanas (parto cesáreo), Apgar 9/10, adequado para a idade gestacional. Bolsa rota no parto, líquido amniótico claro. Passou a apresentar taquipneia. Com 6 horas de vida, ausculta pulmonar normal, retrações intercostais. Hemoglobina 15 g/dl, hematócrito 45%, leucócitos 24.000/mm3 (pró-mielócitos 2%, bastonados 10%, segmentados 60%), PCR 5 mg/l. Diante do quadro, qual o diagnóstico mais provável?", options: ["Doença da membrana hialina", "Sepse neonatal precoce", "Taquipneia transitória do recém-nascido", "Hipertensão pulmonar persistente do recém-nascido"], correctIndex: 2 },
  { id: "hcpa_2022_003", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Paciente com 38 semanas de gestação, sem pré-natal, foi trazida à Emergência Obstétrica em trabalho de parto. Cardiotocografia: FC 60 bpm. USG à beira do leito sem sinais de alarme. Interrupção do parto indicada por bradicardia. Exame clínico normal exceto FC baixa, Apgar 9/9. ECG: bloqueio atrioventricular total. Sobre esse bloqueio de apresentação fetal e neonatal, assinale a assertiva correta.", options: ["Bradicardia fetal persistente não justifica a investigação de bloqueio atrioventricular ao nascimento.", "É pouco frequente que a primeira manifestação de lúpus, artrite reumatoide, síndrome de Sjögren ou esclerose múltipla na gestação esteja relacionada ao diagnóstico de um bloqueio atrioventricular ainda durante a vida fetal.", "Hidropsia fetal é incomum nas formas graves, não sendo um marcador de mau prognóstico.", "Pode ocorrer sem lesões cardíacas estruturais associadas, sendo usualmente secundário à presença de colagenose materna, com ou sem expressão clínica."], correctIndex: 3 },
  { id: "hcpa_2022_004", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido com 39 semanas recebeu alta do alojamento conjunto aos 2 dias de vida (mãe O negativo e neonato O positivo, Coombs direto negativo). Icterícia na zona 2 de Kramer. Bilirrubina transcutânea no polo cefálico 12,5 mg/dl e no tórax 10,5 mg/dl, zona de baixo risco de Buthani. A mãe perguntou se era adequado expor o filho a banho de sol por 10-15 minutos/dia para redução da icterícia neonatal. Que orientação deve ser fornecida a ela?", options: ["Exposição ao sol pode não reduzir a icterícia e, ainda, aumentar o risco de doenças futuras se a exposição solar for desprotegida.", "Exposição ao sol, além de reduzir a icterícia, melhora os níveis de vitamina D.", "Somente exposição à luz solar filtrada está indicada para reduzir a icterícia.", "Banho de sol por 10-15 minutos deve ser feito todas as manhãs antes das 8 horas."], correctIndex: 0 },
  { id: "hcpa_2022_005", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido com 39 semanas (parto vaginal), Apgar 9 no quinto minuto, apresentou taquipneia com 6 horas de vida. Mãe com diagnóstico de infecção urinária. Hemograma da criança: leucocitose, PCR 1 mg/l, hemocultura em análise. Diante desse quadro, qual a conduta mais adequada?", options: ["Aguardar o resultado da hemocultura e a evolução clínica para definir a necessidade de antibioticoterapia.", "Tratar com penicilina procaína intramuscular 1 vez/dia até a definição do antibiograma.", "Tratar com vancomicina intramuscular para cobertura de bactérias como Streptococcus do grupo B, Lysteria monocytogenes e Staphylococcus aureus.", "Tratar com ampicilina e gentamicina intravenosas para cobertura de bactérias como Streptococcus do grupo B, Lysteria monocytogenes e Escherichia coli."], correctIndex: 0 },
  { id: "hcpa_2022_006", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Paciente com HIV positivo, 39 semanas de gestação, chegou ao Centro Obstétrico em trabalho de parto. Qual a principal modificação proposta pelo Ministério da Saúde, através da Nota Técnica emitida em março de 2021, acerca do manejo de recém-nascidos expostos ao HIV?", options: ["Clampeamento tardio do cordão umbilical para mães com carga viral recentemente indetectável.", "Uso do esquema tríplice de antirretrovirais (zidovudina + lamivudina + raltegravir) por 28 dias para os recém-nascidos a termo com alto risco de transmissão vertical do HIV.", "Possibilidade de amamentação ao seio materno se a carga viral materna tiver sido indetectável no terceiro trimestre.", "Dispensa de administração de zidovudina injetável no periparto à gestante se tiver havido boa adesão aos antirretrovirais durante a gestação."], correctIndex: 1 },
  { id: "hcpa_2022_007", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Paciente grávida de 3 meses (gestação prévia e atual sem intercorrências) demonstrou interesse em continuar amamentando o filho de 2 anos após o nascimento do bebê. Qual a recomendação mais adequada nessa situação?", options: ["Desmamar o filho mais velho imediatamente.", "Desmamar o filho mais velho gradualmente antes do nascimento do outro filho.", "Desmamar o filho mais velho assim que o outro filho nascer.", "Manter a amamentação do filho mais velho se essa for a vontade materna."], correctIndex: 3 },
  { id: "hcpa_2022_008", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Lactente de 2 meses apresentando tosse e febrícula há 7 dias. Mãe sem pré-natal, parto vaginal, IG 39 semanas, disúria no terceiro trimestre. Taquipneica, sem retrações, raros sibilos, temperatura axilar 37,5° C. Tosse em staccato. SpO2 95%. Hemoglobina 10,5 g/dl, leucócitos 12.000/mm3 (10% eosinófilos). RX: opacidades bilaterais centrais e leve aprisionamento de ar. Assinale a alternativa que contempla o diagnóstico mais provável e o tratamento adequado.", options: ["Bronquiolite por vírus sincicial respiratório − palivizumabe", "Pneumonia por Streptococcus pneumoniae − cefuroxima", "Pneumonia por Chlamydia trachomatis − azitromicina", "Pneumonia por SARS-CoV-2 − dexametasona"], correctIndex: 2 },
  { id: "hcpa_2022_009", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Dois irmãos, um de 3 e outro de 6 anos, apresentaram escore Z para IMC/Idade de 1,5. Qual a classificação antropométrica do estado nutricional de ambos os irmãos?", options: ["Adequada para as duas crianças", "Risco de sobrepeso para as duas crianças", "Adequada para a criança de 3 anos e sobrepeso para a de 6 anos", "Risco de sobrepeso para a criança de 3 anos e sobrepeso para a de 6 anos"], correctIndex: 3 },
  { id: "hcpa_2022_010", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Lactente de 6 meses foi trazido à UBS, diagnosticado com bronquiolite viral aguda. Afebril, hidratado, mamando bem, sem esforço respiratório. Mãe diagnosticada com covid-19 há 5 dias. Teste PCR da criança também positivo. Estado clínico inalterado. Que conduta deve ser adotada?", options: ["Orientar a mãe sobre a necessidade de reavaliação médica urgente caso surjam sinais clínicos de gravidade.", "Prescrever prednisolona para a criança e revisar suas condições em 24-48 horas.", "Solicitar hemograma, dosagem de proteína C reativa e raio X de tórax para a criança e revisar suas condições em 24 horas.", "Encaminhar a criança para internação hospitalar."], correctIndex: 0 },
  { id: "hcpa_2022_012", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menina de 5 anos foi trazida à Emergência com febre, lesões aftosas e adenite cervical. No último ano, episódios recorrentes de amigdalite com dor abdominal, artralgias, adenomegalias e febre (4 dias), com antibióticos por 10 dias. Adenomegalias não dolorosas bilaterais cervicais, aftas na cavidade oral, amígdalas hiperemiadas sem placas. Hemograma normal, PCR elevada. Que hipótese diagnóstica é a mais provável?", options: ["Febre familiar do Mediterrâneo", "Amigdalite bacteriana de repetição", "Imunodeficiência primária", "Síndrome de febre periódica, estomatite aftosa, faringite e adenite cervical (PFAPA)"], correctIndex: 3 },
  { id: "hcpa_2022_013", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Paciente de 7 anos, com doença de Addison, foi trazido à Emergência por cansaço e fraqueza nos membros inferiores. FC 55 bpm, alargamento do complexo QRS, SpO2 99%. RX de tórax normal, ECG confirmou arritmia. Diante desse quadro, deve-se prescrever, imediatamente, por via intravenosa,", options: ["hidroclorotiazida.", "gluconato de cálcio a 10%.", "soro fisiológico a 20%, em infusão rápida.", "amiodarona."], correctIndex: 1 },
  { id: "hcpa_2022_014", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Na Sala de Emergência Pediátrica, durante o atendimento a um paciente de 10 anos em crise de cetoacidose diabética, com diurese presente, está contraindicado o uso intravenoso de", options: ["soro fisiológico.", "insulina regular.", "bicarbonato de sódio.", "cloreto de potássio."], correctIndex: 2 },
  { id: "hcpa_2022_016", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Durante consulta médica de rotina, adolescente masculino, de 13 anos, submetido a transplante de medula óssea há 1 ano, solicitou orientação sobre a vacina contra HPV. Assinale a assertiva correta conforme recomendação do PNI.", options: ["Indicar esquema de 2 doses com intervalo de 6 meses, porque a idade do paciente é inferior a 14 anos.", "Indicar esquema de 3 doses devido à condição de transplantado de medula óssea.", "Indicar a vacina apenas após os 15 anos.", "Contraindicar a vacina até que se realize a avaliação das imunidades humoral e celular do paciente."], correctIndex: 1 },
  { id: "hcpa_2022_017", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Adolescente de 14 anos vinha apresentando sintomas de asma leve cerca de 3 vezes ao ano e não fazia uso de medicação preventiva. Assinale a alternativa que contém duas opções adequadas para o tratamento inicial dos sintomas, segundo recomendações da GINA.", options: ["Associação de b2-agonista de longa ação com corticosteroide inalatório ou associação de b2-agonista de curta ação com corticosteroide inalatório", "b2-agonista de longa ação ou b2-agonista de curta ação", "b2-agonista de longa ação ou associação de b2-agonista de curta ação com corticosteroide inalatório", "b2-agonista de curta ação ou corticosteroide inalatório"], correctIndex: 0 },
  { id: "hcpa_2022_018", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Assinale a assertiva correta sobre febre em criança.", options: ["Um modo fidedigno para diferenciar febre causada por vírus de febre causada por bactéria é a persistência da recusa alimentar depois da administração de uma dose correta de antipirético.", "Compressas com água fria causam mais desconforto, arrepios e tremores do que qualquer benefício; o recomendável é esponjar o corpo com água morna.", "Administração de dois antipiréticos diferentes em combinação ou alternadamente para reduzir a temperatura aumenta o risco de efeitos adversos e sugere o fenômeno conhecido como febrefobia.", "O risco de dano neurológico por febre aumenta significativamente com temperaturas axilares superiores a 39o C."], correctIndex: 2 },
  { id: "hcpa_2022_019", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Assinale a assertiva correta sobre reposição de fluidos em pacientes pediátricos.", options: ["Uso de Ringer-lactato, por seu alto conteúdo de potássio, está contraindicado para pacientes com sepse.", "Reposição volêmica com grandes volumes de solução salina (solução fisiológica) pode provocar acidose hiperclorêmica.", "Lactente em pausa alimentar deve receber solução fisiológica de manutenção estimada em 100 ml/kg/dia com 5 mEq/kg de sódio e 3 mEq/kg de potássio.", "Balanço hídrico cumulativo positivo e edema após reposição fluídica são achados com pouca relevância clínica para pacientes em choque."], correctIndex: 1 },
  { id: "hcpa_2022_020", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Assinale a alternativa que contempla a sequência correta no atendimento de uma criança em parada cardiorrespiratória (PCR) testemunhada, de acordo com as Diretrizes para Ressuscitação Cardiopulmonar, da American Heart Association (2020).", options: ["Abrir via aérea, fazer respiração artificial, iniciar compressões torácicas e chamar socorro avançado.", "Avaliar a segurança do local, posicionar a criança em superfície rígida, abrir via aérea, fazer respiração artificial, iniciar compressões torácicas e chamar socorro avançado.", "Avaliar a segurança do local, chamar socorro avançado, posicionar a criança em superfície rígida, iniciar compressões torácicas, abrir via aérea e fazer respiração artificial.", "Chamar socorro avançado, posicionar a criança em superfície rígida, abrir via aérea, fazer respiração artificial e iniciar compressões torácicas."], correctIndex: 2 },
  { id: "hcpa_2022_021", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Nuligesta de 25 anos, com diabetes melito tipo 1 desde os 13 anos, uso de insulina lispro em bomba. HbA1c 6,5%, albuminúria negativa. Retinopatia não proliferativa grave. PA 120/80 mmHg. Nódulo móvel de 2x2 cm na mama esquerda, USG sugestiva de fibroadenoma, BI-RADS 2. Que método contraceptivo apresenta risco ou está contraindicado (categoria 3 ou 4 dos critérios de elegibilidade da OMS) para anticoncepção da paciente?", options: ["Anticoncepcional oral combinado", "Pílula de progestágeno isolado", "DIU de cobre", "Implante subdérmico de etonogestrel"], correctIndex: 0 },
  { id: "hcpa_2022_022", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Assinale a assertiva incorreta sobre o acetato de medroxiprogesterona de depósito.", options: ["Se a primeira dose for aplicada nos primeiros 5 dias do ciclo menstrual, o efeito contraceptivo ocorre em 24 horas.", "Após a primeira aplicação, as subsequentes devem ser realizadas a cada 90 dias, com tolerância de 14 dias para mais ou para menos.", "Seu uso prolongado por mais de 2 anos está relacionado a aumento da densidade mineral óssea, independentemente da faixa etária.", "Seu mecanismo de ação contraceptivo promove bloqueio da secreção de LH, aumento da viscosidade do muco e atrofia endometrial."], correctIndex: 2 },
  { id: "hcpa_2022_023", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "O achado visto ao exame citopatológico de colo uterino sugere a possibilidade de contaminação por", options: ["Chlamydia trachomatis.", "Trichomonas vaginalis.", "Herpes simplex tipo 2.", "papilomavírus humano."], correctIndex: 3 },
  { id: "hcpa_2022_024", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Analise a imagem e o POP-Q de uma paciente de 70 anos com pontos Aa +3, Ba +6, C -2, Ap -3, Bp -2. Com base nas informações: I - A paciente realizou histerectomia. II - O sintoma provável é dificuldade para evacuar. III - Pode haver queixas relacionadas a urina residual. Quais são corretas?", options: ["Apenas I e II", "Apenas I e III", "Apenas II e III", "I, II e III"], correctIndex: 1 },
  { id: "hcpa_2022_025", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Nuligesta de 22 anos, menarca aos 14 anos, ciclos regulares, veio à consulta por dor pélvica crônica moderada (7/10), melhora parcial com AINEs, há 1 ano. IMC 19 kg/m2. Uso cíclico de contraceptivo hormonal combinado, mas há 2 anos, após colocação de DIU de cobre, houve piora do quadro. Sem alergias, sintomas GI ou urinários. Exame ginecológico normal. Qual a conduta mais adequada para essa paciente no momento?", options: ["Solicitar dosagem de CA-125.", "Solicitar ultrassonografia pélvica transvaginal.", "Solicitar ressonância magnética pélvica.", "Iniciar tratamento com progesterona."], correctIndex: 3 },
  { id: "hcpa_2022_026", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Nuligesta de 35 anos, menarca aos 13 anos (ciclos regulares de 28 dias, sem dismenorreia), diagnóstico de endometriose peritoneal, tentando gestar há 2 anos, espermocitograma do parceiro normal. Qual o método de escolha para investigação de fator tubário nessa paciente?", options: ["Histerossalpingografia", "Dosagem de IgG para Chlamydia trachomatis", "Histeroscopia", "Ressonância magnética pélvica"], correctIndex: 0 },
  { id: "hcpa_2022_027", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 22 anos consultou por piora importante da acne na face e no dorso nos últimos 6 meses e por amenorreia há 4 meses. PA 135/75 mmHg, IMC 42 kg/m2. Pelos grossos no mento, lábio superior e queixo, acne nodular. Clitóris hipertrófico. Testosterona total 7,13 ng/ml (VR 0,14-0,76), sulfato de DHEA 127 mg/dl (VR 35-430, normal). Que diagnóstico é o mais provável?", options: ["Síndrome dos ovários policísticos", "Deficiência de 21-hidroxilase", "Carcinoma de adrenal", "Tumor de células de Leydig"], correctIndex: 3 },
  { id: "hcpa_2022_028", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "São fatores de risco para o desenvolvimento do câncer de mama", options: ["idade tardia da menarca e obesidade.", "mutação BRCA1 e menopausa precoce (≤ 45 anos).", "presença de fibroadenoma na mama e multiparidade.", "nuliparidade e consumo regular de álcool."], correctIndex: 3 },
  { id: "hcpa_2022_029", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Considere: I - O rastreamento de câncer de ovário é indicado a partir dos 50 anos, com USG transvaginal e CA-125. II - O tipo histológico mais frequente é o cistoadenocarcinoma seroso. III - O uso de anticoncepcional oral combinado é fator de risco. Quais são corretas?", options: ["Apenas I", "Apenas II", "Apenas I e II", "Apenas I e III"], correctIndex: 1 },
  { id: "hcpa_2022_030", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 38 anos teve confirmado o diagnóstico de adenocarcinoma de colo de útero. Assinale a assertiva correta sobre o câncer de colo de útero.", options: ["As neoplasias intraepiteliais cervicais de alto grau apresentam percentual significativo de progressão para neoplasias invasoras ao longo do tempo, justificando-se o tratamento dessas lesões quando diagnosticadas.", "A disseminação é principalmente hematogênica.", "O estadiamento, segundo a FIGO, envolve principalmente a utilização de ressonância magnética com contraste para identificar o crescimento local do tumor.", "O diagnóstico deve estar errado, pois a paciente não se encontra na faixa etária considerada de risco para câncer de colo de útero."], correctIndex: 0 },
  { id: "hcpa_2022_031", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Primigesta de 28 anos, gestação de 39 semanas (risco habitual), procurou o Centro Obstétrico com contrações há 4 horas. Sinais vitais estáveis. Altura uterina 35 cm, 2 contrações irregulares a cada 10 minutos (20 seg), BCF 140 bpm com acelerações transitórias, colo médio, 80% apagado, dilatação de 2 cm. Diante desse quadro, pode-se afirmar que a paciente", options: ["encontra-se no primeiro período do parto.", "encontra-se na fase ativa do trabalho de parto.", "deve receber infusão de ocitocina em bomba para correção da dinâmica uterina.", "deve realizar cardiotocografia para avaliação do bem-estar fetal."], correctIndex: 0 },
  { id: "hcpa_2022_032", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Assinale a alternativa que contém a sequência correta do que ocorre no segundo período do parto (mecanismo de parto).", options: ["Rotação interna, extensão, flexão, desprendimento da apresentação, rotação externa", "Rotação interna, extensão, rotação externa, desprendimento da apresentação", "Flexão, rotação interna, extensão, desprendimento da apresentação, rotação externa", "Flexão, extensão, rotação interna, rotação externa, desprendimento da apresentação"], correctIndex: 2 },
  { id: "hcpa_2022_033", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Assinale a assertiva correta sobre ruptura prematura de membranas (RUPREME) em gestantes atendidas em hospital terciário.", options: ["Na RUPREME pré-termo com conduta conservadora, deve-se utilizar nifedipina até a 34a semana para impedir o trabalho de parto prematuro.", "Para gestantes em qualquer idade gestacional, se houver diagnóstico de infecção intrauterina, estão indicadas internação e interrupção da gestação.", "Se a idade gestacional for > 34 semanas, deve-se utilizar sulfato de magnésio para neuroproteção por 12 horas antes de interromper a gestação.", "Caso a interrupção da gestação ocorra após a 34a semana, não há necessidade de profilaxia para Streptococcus do grupo B se o estado da colonização for desconhecido."], correctIndex: 2 },
  { id: "hcpa_2022_034", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Em casos de sangramento por descolamento prematuro de placenta, em uma gestação com feto com viabilidade e vitalidade, o nascimento deve se dar preferencialmente", options: ["pela via de parto através da qual o nascimento ocorra mais rapidamente.", "por parto vaginal com episiotomia.", "por parto vaginal com fórceps.", "por cesariana."], correctIndex: 1 },
  { id: "hcpa_2022_035", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Assinale a assertiva correta sobre a avaliação do bem-estar fetal.", options: ["Paciente com 23 semanas, normotensa, com eco-Doppler de artérias uterinas alterado, deve ser internada para rastrear pré-eclâmpsia e realizar avaliação com perfil biofísico fetal.", "Paciente com 28 semanas, diabetes gestacional, peso fetal no percentil 80, deve realizar eco-Doppler das artérias umbilicais frequentemente, para prevenir acidose metabólica e óbito fetal inesperado.", "Paciente com 29 semanas, feto com restrição de crescimento e vasodilatação da artéria cerebral média ao eco-Doppler, deve ser internada para receber imediatamente corticosteroide e ter a gestação interrompida após 48 horas.", "Paciente com 34 semanas, avaliação após acidente de carro, sinais de contusão abdominal, inicialmente sem sangramento e sem contrações, feto vivo, deve ser monitorizada por 24 horas."], correctIndex: 3 },
  { id: "hcpa_2022_036", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Primigesta de 16 anos foi trazida à Emergência pelo SAMU desacordada, com convulsões tônico-clônicas. PA 170/120 mmHg, FC 100 bpm, FR 20 mpm. BCF 110 bpm (logo após a convulsão), tônus uterino normal. Colo fechado, apresentação cefálica. Proteinúria de 4+. Qual o diagnóstico mais provável?", options: ["Epilepsia gestacional", "Eclâmpsia", "Síndrome HELLP", "Acidente vascular encefálico (hemorrágico ou isquêmico)"], correctIndex: 1 },
  { id: "hcpa_2022_037", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Considerando a primigesta de 16 anos com eclâmpsia (PA 170/120 mmHg, convulsões, proteinúria 4+), diante do quadro clínico, a conduta mais adequada é administrar", options: ["diazepam (10 mg) + hidralazina (5 mg) por via intravenosa (IV), solicitar tomografia computadorizada de cérebro e indicar cesariana.", "hidantal (10 mg/kg) por IV + nifedipina (5 mg) por via oral (VO), solicitar tomografia computadorizada de cérebro e indicar cesariana.", "midazolan (1 g) por IV + nifedipina (5 mg) por VO + betametasona (12 mg) IM, fazer perfil biofísico fetal e aguardar até a 36a semana.", "sulfato de magnésio (dose de ataque de 4 g) por IV, infundindo 1 g/h em bomba, + hidralazina (5 mg) por IV, aguardar a recuperação do sensório e iniciar a indução do trabalho de parto."], correctIndex: 3 },
  { id: "hcpa_2022_038", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 38 anos, 11 semanas de gestação, moradora da Capital, trouxe glicemia de jejum de 90 mg/dl. IMC pré-gestacional 42 kg/m2, hipertensão arterial. A conduta mais adequada no momento é solicitar", options: ["medida de hemoglobina glicada.", "teste de tolerância a glicose imediatamente.", "teste de tolerância a glicose entre 24-28 semanas.", "repetição da glicemia de jejum entre 24-28 semanas."], correctIndex: 2 },
  { id: "hcpa_2022_039", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Primigesta com 10 semanas de gestação trouxe resultados sorológicos para toxoplasmose, evidenciando IgG não reagente e IgM reagente. Assinale a alternativa que contempla a conduta correta.", options: ["Iniciar espiramicina imediatamente, solicitar teste de avidez para IgG e repetir as dosagens de IgG e IgM em 3-4 semanas para datação da fase aguda.", "Iniciar sulfadiazina, pirimetamina e ácido folínico imediatamente e repetir as dosagens de IgG e IgM em 3-4 semanas.", "Solicitar coleta imediata de material para dosagens de IgG, IgM, IgA e IgE e teste de avidez para IgG e programar cordocentese em 2-3 semanas.", "Solicitar teste de avidez para IgG e oferecer a possibilidade de realização imediata de punção de líquido amniótico para PCR."], correctIndex: 0 },
  { id: "hcpa_2022_040", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 27 anos, G3P2 (último parto há 3 anos), 30 semanas de gestação, portadora de lúpus eritematoso sistêmico, assintomática, VDRL 1:8 e FTA-Abs reagente. Exame físico normal. Sem história de tratamento para sífilis. Qual a conduta correta?", options: ["Prescrever penicilina G benzatina 2,4 milhões de unidades intramuscular para a gestante.", "Prescrever penicilina G benzatina 7,2 milhões de unidades intramuscular para o casal.", "Não é necessário tratar, pois, devido ao lúpus, os exames se mostram falsamente positivos.", "Não é necessário tratar, pois o título de VDRL é baixo."], correctIndex: 1 },
  { id: "hcpa_2022_041", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente de 56 anos, com neoplasia maligna do trato gastrointestinal, queixou-se de perda de 10% do peso corporal em 6 meses e ingestão alimentar em torno de 75% da habitual nas últimas semanas. IMC 17 kg/m2. Na tentativa de reduzir a morbidade cirúrgica em relação ao estado nutricional, qual a conduta mais adequada?", options: ["Agendar o procedimento imediatamente.", "Postergar a cirurgia por 5-14 dias para que o paciente realize terapia nutricional domiciliar com suplementos orais.", "Internar o paciente para realizar terapia nutricional parenteral pré-operatória.", "Prescrever terapia nutricional domiciliar com suplementos orais ou nutrição enteral e realizar a cirurgia após 3 dias do início da terapia."], correctIndex: 1 },
  { id: "hcpa_2022_042", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Oncologia", text: "Paciente feminina, de 45 anos, em quimioterapia neoadjuvante para carcinoma ductal invasor da mama direita, chegou à Emergência com palpitação e mal-estar. Ritmo cardíaco irregular, sudorese, portocath infraclavicular esquerdo. Dor na clavícula esquerda no último ciclo, há 3 dias. ECG: extrassístoles ventriculares. RX de tórax mostrou fragmento de cateter. Qual o diagnóstico e a conduta mais adequada?", options: ["Arritmia devido à presença de fragmento de cateter dentro do ventrículo direito − remoção do fragmento por cateterismo, retirada cirúrgica do reservatório do portocath e programação de novo implante de cateter guiado por ultrassonografia na veia jugular esquerda", "Tromboembolismo pulmonar devido à síndrome de Pinch-off − anticoagulação a pleno", "Arritmia devido à presença de fragmento de cateter dentro do ventrículo esquerdo − solicitação de avaliação de cirurgia cardíaca para remoção do fragmento de cateter com parada circulatória", "Presença de fragmento de cateter dentro do ventrículo esquerdo − remoção do fragmento por cateterismo, retirada cirúrgica do reservatório do portocath e programação de novo implante de cateter guiado por ultrassonografia na veia jugular direita"], correctIndex: 0 },
  { id: "hcpa_2022_043", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente de 68 anos, hospitalizado para cirurgia de urgência de ressecção de tumor intracraniano, apresentou rebaixamento do sensório e vômitos. Cardiopatia isquêmica e insuficiência cardíaca congestiva classe III em tratamento regular. Que fármaco é o de escolha como indutor para a anestesia?", options: ["Propofol", "Fentanil", "Etomidato", "Dexmedetomidina"], correctIndex: 2 },
  { id: "hcpa_2022_044", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente de 38 anos, IMC 48 kg/m2, será submetido a gastroplastia videolaparoscópica eletiva. Após 3 tentativas de intubação sem sucesso, sangramento e edema na via aérea, ventilação sob máscara facial factível, SpO2 94%. Assinale a alternativa que contempla a conduta mais apropriada para o caso.", options: ["Chamar anestesiologista mais experiente para tentar realizar a intubação.", "Inserir máscara laríngea e, caso bem posicionada, seguir o planejamento cirúrgico.", "Realizar cricotireoidostomia.", "Acordar o paciente e planejar intubação por fibrobroncoscopia em outro momento."], correctIndex: 3 },
  { id: "hcpa_2022_045", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Que imagem de uma reconstrução tomográfica em 3D do segmento aortoilíaco é a mais compatível com um quadro de ausência de pulsos femorais, claudicação de nádega e impotência sexual (síndrome de Leriche)?", options: ["Imagem A (aneurisma isolado)", "Imagem B (oclusão aortoilíaca)", "Imagem C (estenose renal bilateral)", "Imagem D (aneurisma ilíaco unilateral)"], correctIndex: 0 },
  { id: "hcpa_2022_046", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente masculino, de 60 anos, com HAS, dislipidemia e tabagismo, realizou USG abdominal identificando aneurisma de aorta abdominal infrarrenal com trombos murais concêntricos, medindo 10 x 4 x 3,5 cm. Com base no caso clínico, assinale a assertiva correta.", options: ["Presença de trombos murais é fator protetor para ruptura.", "Anticoagulação está indicada para reduzir episódios de microembolização periférica.", "Intervenção cirúrgica ou endovascular eletiva não está indicada.", "Ultrassonografia abdominal é suficiente para o acompanhamento de pequenos aneurismas."], correctIndex: 2 },
  { id: "hcpa_2022_047", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente masculino, de 18 anos, vítima de acidente de motocicleta, com trauma contuso de coxa e fratura de fêmur, foi atendido com imobilização inicial e reposição volêmica com cristaloides. Na sondagem vesical, urina escurecida. CPK total 16.000 U/l. Qual das situações abaixo não está associada ao quadro clínico?", options: ["Rabdomiólise", "Hiperpotassemia", "Síndrome compartimental aguda", "Hipercalcemia"], correctIndex: 3 },
  { id: "hcpa_2022_048", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente de 24 anos, no quarto dia pós-operatório de cesariana, referiu desconforto e endurecimento em segmento venoso varicoso da face medial da perna direita, com evolução de 2 dias. Hiperemia local, dor à palpação e incompressibilidade de veia varicosa localizada em topografia da veia safena interna. Assinale a alternativa que contempla o diagnóstico mais provável e a terapia adequada no momento.", options: ["Tromboflebite venosa superficial – administração de anti-inflamatório por via oral", "Tromboflebite venosa superficial – anticoagulação por via oral", "Trombose venosa profunda – anticoagulação por via parenteral", "Trombose venosa profunda – administração de anti-inflamatório por via oral"], correctIndex: 0 },
  { id: "hcpa_2022_049", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente masculino, de 57 anos, com dificuldade para engolir alimentos sólidos há 4 meses e emagrecimento de 9 kg. RX contrastado de esôfago realizado. Que diagnóstico é o mais provável?", options: ["Acalásia", "Carcinoma do esôfago", "Estenose péptica", "Megaesôfago chagásico"], correctIndex: 1 },
  { id: "hcpa_2022_050", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente de 45 anos foi trazida à Emergência com dor e distensão abdominal progressiva há 3 dias e, há 4 dias, náuseas, vômitos e parada de eliminação de flatos e fezes. Histerectomia há 8 anos. Regular estado geral, abdômen distendido e doloroso, sem irritação peritoneal. Ampola retal vazia. RX de abdômen agudo reproduzido. Qual a mais provável causa desse quadro clínico?", options: ["Neoplasia de sigmoide", "Volvo de ceco", "Bridas", "Hérnia interna"], correctIndex: 2 },
  { id: "hcpa_2022_051", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Dermatologia", text: "Paciente masculino, de 56 anos, consultou por lesão de pele no dorso, observada há muitos anos, mas com crescimento e mudança de cor nos últimos meses. Sem prurido ou sangramento. Sem histórico pessoal ou familiar de melanoma. Maior diâmetro de 8 mm. Diante desse quadro clínico, qual a conduta mais adequada?", options: ["Biópsia excisional da lesão com margem mínima de pele aparentemente normal (1-2 mm).", "Biópsia incisional com navete cirúrgica, incluindo borda aparentemente mais ativa.", "Biópsias incisionais com punch em pelo menos 3 áreas mais suspeitas.", "Exérese da lesão com margem mínima de pele aparentemente normal (1-2 cm)."], correctIndex: 0 },
  { id: "hcpa_2022_052", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Assinale a assertiva correta sobre o tratamento cirúrgico de câncer gástrico.", options: ["A laparoscopia diagnóstica está indicada nos tumores precoces.", "A reconstrução em Y de Roux deve ser realizada apenas na gastrectomia total.", "As margens cirúrgicas devem ser maiores nos tumores do tipo difuso.", "O benefício da gastrectomia por laparoscopia é evidente, principalmente nos tumores mais avançados."], correctIndex: 2 },
  { id: "hcpa_2022_053", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Quatro pacientes relatam excesso de peso, com múltiplas tentativas de perda de peso nos últimos 2 anos, sem sucesso. Qual deles não se enquadra nos critérios de indicação para cirurgia bariátrica?", options: ["Paciente masculino, de 28 anos, IMC de 42 kg/m2, sem comorbidades.", "Paciente feminina, de 36 anos, IMC de 37 kg/m2, com HAS de difícil controle.", "Paciente feminina, de 42 anos, IMC de 36 kg/m2, com estigmatização social e depressão relacionadas à obesidade.", "Paciente masculino, de 51 anos, IMC de 33 kg/m2, com esteatose hepática, dislipidemia, osteoartrose dos joelhos e DRGE."], correctIndex: 3 },
  { id: "hcpa_2022_054", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Ao se avaliar um paciente com suspeita de isquemia mesentérica aguda, que exame é o mais indicado para estabelecer o diagnóstico?", options: ["Ressonância magnética de abdômen", "Angiotomografia abdominal", "Arteriografia de vasos mesentéricos", "Ultrassonografia com estudo Doppler de vasos mesentéricos"], correctIndex: 1 },
  { id: "hcpa_2022_055", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Nos quadros típicos de apendicite aguda, a dor migratória, que deixa de ser periumbilical ou difusa e se torna localizada na fossa ilíaca direita, é causada por", options: ["irritação de nervos parassimpáticos.", "irritação do peritônio parietal.", "abscesso retrocecal.", "peritonite difusa."], correctIndex: 1 },
  { id: "hcpa_2022_056", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Assinale a assertiva correta sobre enxertos e retalhos, técnicas fundamentais em cirurgia plástica.", options: ["A transferência de tecido livre microvascular constitui uma técnica de complexidade menor do que a de retalhos pediculados.", "As linhas de expressão facial de pele têm importância na tensão e localizam-se paralelas ao músculo subjacente.", "Um enxerto de pele pode ser colocado sobre o periósteo íntegro.", "Não se realiza enxerto em malha sobre áreas irregulares."], correctIndex: 2 },
  { id: "hcpa_2022_057", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente de 38 anos sofreu queda de uma escada em casa, caindo em piso duro. Levado à Emergência, 7 pontos pela Escala de Coma de Glasgow, intubado. Hemiplegia direita, pupilas isocóricas e fotorreagentes. TC de crânio: fratura à esquerda e hematoma extradural, com desvio das estruturas da linha média. Que conduta é a mais adequada neste momento?", options: ["Internação em CTI e monitorização da pressão intracraniana, por apresentar menos de 8 pontos pela ECG.", "Internação em CTI com avaliação neurológica a cada 2 horas.", "Internação em CTI e repetição da tomografia computadorizada em 6 horas.", "Encaminhamento ao Centro Cirúrgico para remoção do hematoma por craniotomia."], correctIndex: 3 },
  { id: "hcpa_2022_058", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente de 60 anos, intubado há 7 dias por pneumonia por covid-19, apresentou piora dos parâmetros ventilatórios devido a pneumotórax à esquerda. Após drenagem, reexpansão completa do pulmão, porém com escape aéreo persistente (15% do volume corrente). Em relação ao dreno de tórax, que conduta deve ser adotada?", options: ["Manter o dreno e observar o escape aéreo.", "Inserir um segundo dreno.", "Realizar pleurodese pelo dreno com agente esclerosante.", "Indicar pleuroscopia para sutura ou ressecção da fístula."], correctIndex: 0 },
  { id: "hcpa_2022_059", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Na anamnese de um paciente com doença orificial, qual a queixa mais sugestiva do diagnóstico de fissura anal?", options: ["Prurido anal intenso", "Dor evacuatória", "Sangramento anal", "Esforço evacuatório"], correctIndex: 1 },
  { id: "hcpa_2022_060", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "A hiperplasia nodular estromal (hiperplasia prostática benigna) se desenvolve na", options: ["zona anterior (área fibromuscular).", "zona periférica (70% do volume da próstata normal).", "zona central (25% do volume da próstata normal).", "zona de transição (5% do volume da próstata normal)."], correctIndex: 3 },
  { id: "hcpa_2022_061", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Qual dos casos tem indicação de exames cardiológicos complementares para avaliação pré-operatória?", options: ["Paciente feminina, de 25 anos, sem comorbidades, internada para colocação de prótese mamária eletiva.", "Paciente masculino, de 42 anos, com HIV (em uso de dolutegravir, lamivudina, tenofovir), HAS e DM controlados, internado para postoplastia.", "Paciente feminina, de 46 anos, sem comorbidades, internada para duodenopancreatectomia por neoplasia de pâncreas.", "Paciente feminina, de 51 anos, sem uso prévio de medicamentos, com sopro cardíaco e insuficiência mitral leve, assintomática, para passagem de duplo J por cálculo urinário."], correctIndex: 2 },
  { id: "hcpa_2022_062", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Paciente feminina, de 69 anos, procurou a Emergência por dor precordial há 5 horas. Diabetes e hipertensão de controle irregular. PA 166/72 mmHg, FC 108 bpm, Killip II. ECG reproduzido. O hospital com hemodinâmica pode ser acessado em aproximadamente 70 minutos. A estratégia com melhor expectativa de benefício para a paciente é", options: ["administrar estreptoquinase imediatamente e programar a transferência para outro hospital somente para terapia de resgate, se houver falha na reperfusão farmacológica.", "administrar dupla antiagregação plaquetária e nitroglicerina intravenosa e repetir o ECG em 30 minutos.", "administrar alteplase intravenosa associada a heparina não fracionada por 24 horas e programar a transferência para hospital com serviço de hemodinâmica em 6-24 horas.", "transferir a paciente para hospital com serviço de hemodinâmica para realização de angioplastia primária."], correctIndex: 3 },
  { id: "hcpa_2022_063", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Qual dos casos tem indicação de profilaxia para endocardite, segundo as recomendações atuais?", options: ["Paciente com prótese valvar mitral que será submetido a colonoscopia com biópsia.", "Paciente com cardiopatia congênita cianótica não corrigida que será submetido a procedimento dentário invasivo.", "Paciente com prolapso valvar mitral com regurgitação moderada que será submetido a procedimento dentário invasivo.", "Paciente com história de endocardite que será submetido a biópsia renal."], correctIndex: 3 },
  { id: "hcpa_2022_064", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Paciente de 30 anos foi encaminhada ao Serviço de Endocrinologia por pretender submeter-se a cirurgia bariátrica. Peso usual de 65 kg, ganho de 40 kg nos últimos 5 anos. Peso 105 kg, altura 162 cm (IMC 40 kg/m2). Todos os achados abaixo levam à suspeita de causa secundária de obesidade, exceto um. Assinale-o.", options: ["Estrias claras de 0,5 cm de largura no abdômen", "Dificuldade para levantar da cadeira por fraqueza muscular proximal", "Glicemia de jejum de 45 mg/dl acompanhada de palpitações e sudorese", "Fratura em cunha na coluna vertebral e densitometria mineral óssea com escores T -2,5 e Z -3,5"], correctIndex: 0 },
  { id: "hcpa_2022_065", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Dermatologia", text: "Paciente de 32 anos, previamente hígido, veio à consulta por lesão pruriginosa, eventualmente dolorosa (\"ferroadas\") na perna direita há 1 semana. Trilha próxima a uma cachoeira dias antes. Lesão nodular, levemente eritematosa, com orifício central e mínima secreção serosa, sem secreção purulenta. Assinale a assertiva correta.", options: ["A eliminação mecânica do agente causador abrevia o quadro dermatológico.", "O quadro é autolimitado na maioria dos casos, se resolvendo no máximo em 2 semanas.", "Analgesia e antibióticos tópicos são suficientes para resolver o quadro dermatológico.", "A reação cutânea possivelmente tenha ocorrido a partir de uma infestação por pulga."], correctIndex: 0 },
  { id: "hcpa_2022_066", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Paciente de 45 anos, com obesidade, foi hospitalizado por covid-19. Dexametasona 6 mg/dia e oxigênio 5 l/min. Glicemias capilares > 200 mg/dl nos dois primeiros dias, insulina em esquema basal-bolus. Desconhecia diagnóstico prévio de diabetes. Assinale a assertiva correta sobre a hiperglicemia.", options: ["O diagnóstico de DM já está confirmado, pois o paciente apresenta duas glicemias capilares ao acaso > 200 mg/dl.", "Duas glicemias de jejum > 126 mg/dl durante a internação confirmam o diagnóstico de DM prévio à hospitalização.", "Hemoglobina glicada (HbA1c) < 6,5% confirma o diagnóstico de hiperglicemia de estresse.", "Não é possível diferenciar DM prévio de hiperglicemia de estresse, tendo como base os resultados de glicemias ou HbA1c obtidos durante a internação."], correctIndex: 2 },
  { id: "hcpa_2022_067", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Gastroenterologia", text: "Assinale a assertiva correta sobre diarreia por clostridioides.", options: ["É frequentemente associada a hematoquezia e melena.", "Idade > 65 anos e uso de inibidores da bomba de prótons são fatores de risco.", "Megacólon pode ser definido ao raio X como cólon com > 5 cm de diâmetro.", "Transplante fecal é a primeira opção de tratamento na recorrência."], correctIndex: 1 },
  { id: "hcpa_2022_068", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Gastroenterologia", text: "Paciente masculino, de 75 anos, DM, HAS, uso crônico e por conta própria de AINE, procurou a Emergência por hematêmese e dor abdominal há 12 horas. Mucosas úmidas e descoradas, fácies de dor, temperatura 36,8o C, PA 90/60 mmHg. Que achado do exame físico se relaciona com a presença de úlcera gástrica ou duodenal perfurada?", options: ["Dor no quadrante inferior direito à palpação do quadrante inferior esquerdo", "Dor à palpação do hipocôndrio direito durante a inspiração profunda", "Desaparecimento da macicez e aparecimento de hipertimpanismo na região hepática à percussão", "Equimose periumbilical"], correctIndex: 2 },
  { id: "hcpa_2022_069", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Hematologia", text: "Paciente feminina, de 21 anos, veio à consulta com cansaço. Hemoglobina 9,6 g/dl, RDW aumentado (índice de anisocitose), Coombs positivo 3+/4. Qual dos achados laboratoriais é esperado nesse quadro?", options: ["Reticulocitose", "Leucócitos fragmentados", "Microcitose", "Capacidade ferropéxica aumentada"], correctIndex: 0 },
  { id: "hcpa_2022_070", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Paciente de 82 anos, DPOC (GOLD D), oxigênio contínuo domiciliar há 3 anos, foi trazido à Emergência com dispneia em repouso há 7 dias, sem conseguir se alimentar. 7 internações no último ano. Há 1 ano não conseguia colocar a própria roupa sem auxílio devido à dispneia. Sem secreção respiratória nem febre. Emagrecido, taquidispneico, taquicárdico, SpO2 91%. Sem evidência de quadro agudo infeccioso ou embólico. Disse querer somente alívio para sua falta de ar. A conduta mais adequada, neste momento, é prescrever", options: ["benzodiazepínico.", "corticosteroide.", "opioide parenteral em baixa dose.", "opioide por nebulização."], correctIndex: 2 },
  { id: "hcpa_2022_071", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Paciente de 30 anos foi internada por febre, cefaleia e vômitos há 7 dias. TC de crânio normal. Punção lombar: pressão de abertura 300 mmH2O, 100 leucócitos/mm³ (99% linfócitos), proteína 300 mg/dl, glicose 20 mg/dl (sérica 120), BAAR negativo, PCR positivo para Mycobacterium tuberculosis. Anti-HIV positivo, CD4 30 células/mm³, carga viral 150.000 cópias/ml. Qual a conduta mais adequada?", options: ["Aguardar a cultura para confirmar o diagnóstico antes de iniciar o tratamento.", "Iniciar imediatamente o esquema RHZE (rifampicina + isoniazida + pirazinamida + etambutol) e a terapia antirretroviral.", "Iniciar imediatamente o esquema RHZE + prednisona e adiar por 2 semanas o início da terapia antirretroviral.", "Iniciar imediatamente o esquema RHZE + prednisona e adiar por 8 semanas o início da terapia antirretroviral."], correctIndex: 3 },
  { id: "hcpa_2022_072", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Paciente masculino, de 45 anos, sem comorbidades, com cefaleia, prostração, tosse seca eventual e febre até 38,3o C há 5 dias. Teste de antígeno para covid-19 há 2 dias, negativo. Contato com colega com sintomas respiratórios. Sinais vitais estáveis, SpO2 98%. Em relação à investigação diagnóstica para covid-19 neste momento, assinale a assertiva correta.", options: ["Seria indicado realizar um teste molecular devido à sua maior sensibilidade quando comparado ao teste de antígeno.", "Seria indicado repetir o teste de antígeno, pois forneceria um resultado mais rápido e, se negativo, descartaria o diagnóstico.", "Tanto o teste molecular como o de antígeno apresentam sensibilidade semelhante, porém o PCR é mais específico, sendo, portanto, o exame indicado.", "Tanto o teste de PCR como o de antígeno apresentam baixa sensibilidade neste momento da infecção, razão pela qual deveria ser realizada uma tomografia computadorizada de tórax."], correctIndex: 0 },
  { id: "hcpa_2022_073", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Paciente de 55 anos foi hospitalizada por insuficiência cardíaca, evoluindo para parada cardíaca. Potássio 3 mEq/l, magnésio 1,2 mg/dl, creatinina 0,8 mg/dl. ECG mostra ritmo inicial de fibrilação ventricular/TV polimórfica. Assinale a alternativa que contempla o tratamento apropriado para a paciente.", options: ["Choque sincronizado e reposição de potássio e magnésio", "Choque sincronizado e reposição de potássio e bicarbonato", "Choque não sincronizado, reposição de magnésio e administração de furosemida", "Choque não sincronizado e reposição de magnésio apenas"], correctIndex: 3 },
  { id: "hcpa_2022_074", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Nefrologia", text: "Paciente de 56 anos, HAS desde os 50, obesidade (IMC 31 kg/m2), diabetes tipo 2 há 1 ano. Uso de enalapril, hidroclorotiazida, metformina e glimepirida. Creatinina 1,7 mg/dl (CKD-EPI 46 ml/min), potássio 4,9 mg/dl, HbA1c 8,9%, albuminúria 256 mg/l. Visto que apresenta doença renal do diabetes, recebeu, para esse diagnóstico, a prescrição de", options: ["redução de 50% na dose de metformina.", "inibidor do SGLT-2 (cotransportador sódio-glicose 2).", "análogo do GLP-1 (peptídio glucagon-like-1).", "espironolactona."], correctIndex: 1 },
  { id: "hcpa_2022_075", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Assinale a assertiva correta sobre a indicação de exames de imagem no atendimento emergencial de pacientes com acidente vascular cerebral (AVC).", options: ["Tomografia computadorizada de crânio sem contraste tem baixa sensibilidade para detecção de AVC hemorrágico (hemorragia intraparenquimatosa).", "A imagem ponderada em T2 de ressonância magnética de crânio é mais sensível do que a de tomografia computadorizada de crânio sem contraste para o diagnóstico de AVC isquêmico nas 2 horas subsequentes ao início dos sintomas.", "A adição de contraste na tomografia computadorizada de crânio aumenta a chance de detecção de AVC agudo.", "Tomografia computadorizada de crânio é o exame de escolha para o atendimento de AVC agudo na maioria dos casos."], correctIndex: 3 },
  { id: "hcpa_2022_076", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Hematologia", text: "Paciente de 39 anos foi internada para tratamento de complicações relacionadas a um linfoma. Peso 60 kg, soro fisiológico intravenoso 0,9% (30 ml/hora), fluconazol para candidíase sistêmica. Vômitos e câimbras hoje. Uso de filgrastima recentemente após o nadir da quimioterapia. Potássio caindo de 4,3 para 2,3 mEq/l ao longo dos dias, com queda de leucócitos e recuperação medular subsequente. Qual a principal causa para a hipopotassemia?", options: ["Hiper-hidratação e diurese excessiva", "Recuperação medular", "Uso de fluconazol", "Perda de secreções pelo trato gastrointestinal"], correctIndex: 0 },
  { id: "hcpa_2022_077", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Paciente com DPOC moderada (GOLD 2), tratamento contínuo com formoterol inalatório, permanecia com dispneia aos pequenos esforços, mas sem exacerbações nos últimos 12 meses. Qual o escalonamento de tratamento mais adequado?", options: ["Manter formoterol de uso contínuo por mais 3 meses e reavaliar.", "Adicionar um anticolinérgico de longa ação de uso contínuo.", "Adicionar um b2-agonista de curta ação se houver dispneia.", "Adicionar um corticosteroide inalatório de uso contínuo."], correctIndex: 3 },
  { id: "hcpa_2022_078", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Paciente masculino, de 38 anos, tosse produtiva, hemoptise, febre ocasional e perda de peso de 7 kg, quadro iniciado há 3 meses. RX de tórax realizado. Que hipótese diagnóstica é a mais provável?", options: ["Carcinoma epidermoide", "Metástases pulmonares", "Tuberculose", "Fibrose cística"], correctIndex: 2 },
  { id: "hcpa_2022_079", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Psiquiatria", text: "Paciente de 25 anos, ataques súbitos de palpitação, sudorese, tremor, falta de ar, dor torácica, tonturas e medo de morrer. Exames sem alterações. Receio de sair de casa, preocupação constante com nova crise. Acerca desse transtorno (pânico), assinale a assertiva correta.", options: ["Os tratamentos de primeira linha são os inibidores seletivos da recaptação de serotonina, venlafaxina e terapia cognitivo-comportamental.", "Benzodiazepínico de uso contínuo por longo prazo está indicado.", "Indivíduos do sexo masculino são mais frequentemente afetados por esse transtorno do que os do feminino, em uma razão em torno de 2:1.", "Cerca de 70% dos pacientes com esse transtorno não respondem à intervenção de primeira linha."], correctIndex: 0 },
  { id: "hcpa_2022_080", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Reumatologia", text: "Paciente feminina, de 67 anos, obesidade e HAS, dor no quadril direito e joelho esquerdo há 1 ano. Rigidez matinal de 30 minutos, piora ao subir e descer escadas. Dor à mobilização passiva extrema, discreto aumento de temperatura e volume não depressível. Nodulações em IFDs de ambas as mãos (osteoartrite). Qual a conduta terapêutica mais adequada?", options: ["Uso de hidroxicloroquina", "Uso de metotrexato", "Prática de exercícios aeróbicos e de resistência", "Artroplastia"], correctIndex: 2 },
  { id: "hcpa_2022_081", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Assinale a assertiva correta sobre medicina baseada em evidências.", options: ["A razão de verossimilhança positiva indica quantas vezes é maior a possibilidade de a pessoa ter a doença quando um teste é positivo.", "A utilidade de um teste diagnóstico é maior se a probabilidade pré-teste da doença for < 25%.", "Especificidade de um teste é a capacidade de identificar os indivíduos doentes entre as pessoas testadas na população.", "Redução absoluta de risco é a taxa de eventos no experimento subtraída da taxa de eventos nos controles."], correctIndex: 0 },
  { id: "hcpa_2022_082", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em 2020, foram registradas no Brasil 194.976 mortes por covid-19, população estimada de 213.320.748 habitantes. A que medida corresponde o índice calculado de 914 óbitos por covid-19 por milhão de habitantes em 2020?", options: ["À taxa de letalidade", "À taxa de mortalidade", "À letalidade proporcional", "À mortalidade proporcional"], correctIndex: 1 },
  { id: "hcpa_2022_083", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Qual o numerador usado para o cálculo da taxa de incidência de uma doença referente a uma determinada população estudada?", options: ["Todos os casos diagnosticados durante um estudo transversal.", "Todos os casos novos diagnosticados durante o período de seguimento.", "Todos os indivíduos doentes presentes no início do período de seguimento.", "Todos os indivíduos doentes presentes no final do período de seguimento."], correctIndex: 1 },
  { id: "hcpa_2022_084", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em um centro médico acadêmico, foi realizado um estudo envolvendo 48 parturientes com feto único, cefálico e a termo, para determinar desfechos materno e neonatal de acordo com a aplicação ou não de estimulação elétrica nervosa transcutânea, de forma aleatória, para alívio da dor do parto. Qual o delineamento desse estudo?", options: ["Estudo transversal", "Estudo de coorte", "Ensaio clínico randomizado", "Estudo de caso-controle"], correctIndex: 2 },
  { id: "hcpa_2022_085", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Como medida de contenção à pandemia de covid-19, um município brasileiro, na fronteira do Brasil com a Argentina, decidiu estabelecer e executar novas normas de vigilância sanitária, impedindo o trânsito de cargas e pessoas entre os 2 países. Essa conduta está de acordo com a legislação?", options: ["Sim. De acordo com a Lei Orgânica da Saúde (Lei no 8.080/1990), é atribuição da gestão municipal do SUS estabelecer normas e executar a vigilância sanitária de portos, aeroportos e fronteiras.", "Sim. De acordo com o Decreto no 7.508/2011, as Regiões de Saúde em fronteira poderão criar normas que regem as relações internacionais em emergência sanitária.", "Não. De acordo com a Lei Orgânica da Saúde, é atribuição da gestão municipal do SUS colaborar com a União e os Estados na execução da vigilância sanitária de portos, aeroportos e fronteiras.", "Não. De acordo com o Decreto no 7.508/2011, é atribuição das Comissões Intergestoras pactuar as ações emergenciais em casos de emergência sanitária."], correctIndex: 2 },
  { id: "hcpa_2022_086", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "A Portaria no 2.979/2019 criou o Programa Previne Brasil, novo modelo de financiamento para a APS e ESF, substituindo a PNAB de 2011. A nova sistemática considera", options: ["o número de pessoas registradas em equipes de APS e ESF, ponderado por critérios de vulnerabilidade socioeconômica, perfil demográfico e localização geográfica, acrescido pelo pagamento por resultados e por incentivos financeiros para ações prioritárias do MS.", "o número de pessoas que vivem no município (PAB fixo), acrescido pelo PAB variável, composto por critérios de vulnerabilidade regionais e metas atingidas pelo PMAQ.", "o número de pessoas que vivem no município (PAB fixo), acrescido pelo PAB variável, composto por valores por número de equipes completas de ESF e odontológicas.", "nos serviços prestados (fee for service), o número de equipes completas de ESF, acrescido pelo número de UBSs e metas de vacinação, pré-natal e programas prioritários."], correctIndex: 0 },
  { id: "hcpa_2022_087", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Segundo o art. 196 da Constituição Federal, a saúde é direito de todos e dever do Estado. Como muitos artigos sobre financiamento do SUS foram vetados na promulgação, o SUS passou a ser financiado por legislações infraconstitucionais. Assinale a alternativa que contempla a legislação que representou o maior impacto para o subfinanciamento da Atenção Básica no SUS.", options: ["Criação do Piso de Atenção Básica (PAB) na Norma Operacional Básica de 1996 com transferência de recursos aos municípios em 1998.", "Redução, em 2004, do percentual da COFINS incidente na receita de empregadores e empresas.", "Emenda Constitucional no 51/2006, que obriga a contratação direta pelos Estados, DF e Municípios dos ACS e Agentes de Endemias, onerando os gestores municipais sem contrapartida federal.", "Emenda Constitucional no 95/2016, que cria um teto de gastos públicos cujas metas poderão ser revisadas em 10 anos."], correctIndex: 3 },
  { id: "hcpa_2022_088", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Assinale a assertiva correta sobre internações hospitalares por condições sensíveis à Atenção Primária (CSAP).", options: ["Incluem-se, entre as condições sensíveis, as internações por diabetes, hipertensão, pneumonia e partos e constituem indicadores de baixo acesso aos serviços de saúde.", "Incluem-se, entre as condições sensíveis, as que poderiam ser tratadas com internações curtas em hospitais de baixa complexidade e assistidas por médicos de família.", "Taxas elevadas de internações hospitalares por condições sensíveis podem indicar baixo acesso aos serviços de Atenção Primária por parte da população ou oferta de uma Atenção Primária de baixa qualidade.", "Dependendo da condição, o paciente é encaminhado para internação após consulta na Atenção Primária, indicando eficiência do sistema de referência e contrarreferência."], correctIndex: 2 },
  { id: "hcpa_2022_089", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Assinale a assertiva incorreta sobre o planejamento da saúde no Sistema Único de Saúde (SUS).", options: ["O planejamento é obrigatório para a iniciativa privada que oferece serviços complementares ao SUS.", "O planejamento é obrigatório para os entes públicos e compatibiliza os instrumentos de planejamento da saúde, como o Plano de Saúde, com os instrumentos de planejamento e orçamento de governo, como o Plano Plurianual.", "É vedada a transferência de recursos para o financiamento de ações na área da saúde não previstas nos Planos de Saúde, exceto em situações emergenciais ou de calamidade pública.", "O relatório de gestão, que apresenta os resultados do Plano de Saúde, deve ser submetido ao Conselho de Saúde do respectivo gestor do SUS."], correctIndex: 0 },
  { id: "hcpa_2022_090", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Assinale a assertiva incorreta sobre o papel da Atenção Primária à Saúde (APS) na rede de serviços.", options: ["Países com maior pontuação na avaliação da APS apresentam efeitos positivos na efetividade, na eficiência e na equidade do sistema de saúde.", "Países de alta renda, em que a APS desempenha forte papel na organização do sistema de saúde, apresentam melhores resultados na saúde da população, menores taxas de hospitalização desnecessárias e menor desigualdade socioeconômica.", "Há evidências de que a APS, quando desempenha forte papel na organização do sistema de saúde, promove redução de custos nos sistemas sanitários.", "Não há impacto da APS com forte papel na organização do sistema de saúde em países de baixa e média rendas devido às desigualdades na distribuição dos determinantes sociais da saúde."], correctIndex: 3 },
  { id: "hcpa_2022_091", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Sobre o aumento da cobertura do Programa Saúde da Família e os indicadores mortalidade infantil e mortalidade na infância, assinale a assertiva incorreta.", options: ["Houve redução de 4,6% na mortalidade infantil para cada 10% de aumento na cobertura populacional do Programa Saúde da Família.", "A cobertura do Programa Saúde da Família não teve impacto na mortalidade na infância (crianças com menos de 5 anos).", "Houve redução na mortalidade infantil pós-neonatal com o efeito combinado de aumento das coberturas dos Programas Saúde da Família e Bolsa Família.", "Nas populações de menor quintil de renda, a expansão do Programa Saúde da Família teve maior impacto em promover equidade do que o Programa Nacional de Vacinação."], correctIndex: 1 },
  { id: "hcpa_2022_092", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ética Médica", text: "Assinale a assertiva correta sobre o ambiente de atendimento médico por meio de uma ligação telefônica.", options: ["A identificação de ruídos ambientais, alheios à consulta, não pode suscitar a interrupção do atendimento por razões éticas.", "No decorrer do atendimento telefônico, é possível detectar a necessidade de atendimento presencial urgente, mesmo que a pessoa em avaliação não mencione nenhuma queixa ou sintoma de alerta.", "Um resultado de exame positivo para doença sexualmente transmissível não pode, em hipótese alguma, ser informado pelo profissional para um terceiro durante um atendimento telefônico.", "A criptografia de ponta-a-ponta utilizada por aplicativos de mensagem, como o Whatsapp, faz dos dispositivos móveis um meio eficaz e seguro de armazenamento de imagens e exames."], correctIndex: 2 },
  { id: "hcpa_2022_093", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Paciente de 55 anos retornou à UBS com resultado de HIV positivo. Assintomática, leucócitos normais, sem perda de peso. Considere: I - Instituição precoce da TARV reduz o risco de tuberculose, a principal causa de mortalidade por HIV. II - A vacinação contra pneumococo (23-valente) está indicada em esquema de 2 doses com intervalo de 5 anos, independentemente da idade. III - Mesmo em situações de alto risco, a TARV não deve ser iniciada sem a contagem de CD4. Quais são corretas?", options: ["Apenas I", "Apenas II", "Apenas I e II", "Apenas II e III"], correctIndex: 2 },
  { id: "hcpa_2022_095", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Paciente masculino, de 34 anos, com asma, consultou por tosse iniciada há 3 dias. Salbutamol spray (2 jatos a cada 4 horas), com discreta melhora. Consegue dialogar sem interrupção. Sibilos difusos, FR 24 mpm, FC 110 bpm, SpO2 96%. Assinale a alternativa que contempla a(s) conduta(s) mais adequadas para o caso.", options: ["Encaminhar o paciente imediatamente ao Serviço de Urgência por apresentar possível infecção por covid-19, sintomas graves e fator de mau prognóstico (asma).", "Instituir tratamento de resgate com b2-agonista spray oral por 1 hora; revisar a técnica inalatória; iniciar corticosteroide e antibiótico por via oral; notificar e solicitar RT-PCR para covid-19.", "Instituir tratamento de resgate com b2-agonista spray oral por 1 hora; iniciar corticosteroide por via oral; encaminhar o paciente ao Serviço de Urgência por sintomas graves e fator de mau prognóstico.", "Instituir tratamento de resgate com b2-agonista spray oral por 1 hora; revisar a técnica inalatória; notificar e solicitar teste de RT-PCR para covid-19."], correctIndex: 3 },
  { id: "hcpa_2022_096", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Pediatria", text: "A primeira consulta de um recém-nascido na UBS deve ser realizada na primeira semana de vida, momento em que", options: ["a amamentação poderá ser supervisionada, e o peso, aferido.", "a segunda dose da vacina contra hepatite B poderá ser realizada.", "o resultado do teste do pezinho, realizado nas primeiras 24 horas de vida, poderá ser visualizado.", "os testes do olhinho e da orelhinha terão indicação de realização em serviços de referência."], correctIndex: 0 },
  { id: "hcpa_2022_097", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ética Médica", text: "Paciente de 28 anos consultou na Atenção Primária por descobrir-se grávida e não desejar levar adiante a gestação, resultado de relação sexual não consentida com seu parceiro, em relacionamento conflituoso com agressão física. Última menstruação há 7 semanas. Com base no quadro, que conduta é a mais adequada?", options: ["Antes de encaminhar a paciente a um serviço de referência, orientá-la para que procure uma delegacia para fazer um boletim de ocorrência, imprescindível para o atendimento.", "Informar à paciente que o caso se enquadra nas situações previstas em lei para realização de aborto; se ela desejar, encaminhar a um serviço de referência, por se tratar de gestação resultante de violência sexual.", "Encaminhar a paciente a um serviço de referência para realização de um aborto legal após a comprovação do estupro.", "Não encaminhar a paciente para a realização de um aborto legal, pois, em todas as situações, o aborto é ilegal no Brasil."], correctIndex: 1 },
  { id: "hcpa_2022_098", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Medicina do Trabalho", text: "Assinale a assertiva correta sobre a comunicação de acidente do trabalho (CAT) e o afastamento do trabalho.", options: ["Qualquer trabalhador (incluindo titular/sócio de empresa, autônomo e empregado doméstico) tem direito de comunicar ao INSS um acidente de trabalho emitindo uma CAT, visando receber auxílio econômico.", "A CAT somente deverá ser emitida quando o empregado for efetivamente afastado do trabalho.", "Não é permitido que o acidentado ou um familiar emitam a CAT, apenas a empresa tem esse poder.", "Caso seja necessário afastamento por período superior a 15 dias, o trabalhador deve procurar o Posto de Benefícios do INSS e se submeter à perícia médica, pois cabe ao perito decidir se o trabalhador é capaz de retornar às suas atividades laborais."], correctIndex: 3 },
  { id: "hcpa_2022_099", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Medicina do Trabalho", text: "Assinale a assertiva correta sobre perda auditiva induzida por ruído (PAIR).", options: ["Pode ser neurossensorial ou de condução.", "É uma perda auditiva irreversível e, geralmente, unilateral.", "Há progressão constante da perda auditiva, mesmo cessando a exposição ao ruído.", "O portador de PAIR pode queixar-se de zumbidos e desenvolver intolerância a sons intensos."], correctIndex: 3 },
  { id: "hcpa_2022_100", banca: "HCPA", cycle: "Ciclo Clínico", subject: "Ética Médica", text: "Assinale a assertiva incorreta relativa a condutas médicas segundo o Código de Ética Médica.", options: ["A decisão compartilhada com a família de que não serão mais adotadas medidas de suporte vital ao paciente terminal, sem possibilidade de tratamento curativo, é eticamente aceitável, mesmo que possa apressar a morte.", "O não fornecimento de atestado de óbito a idoso que tenha falecido no CTI por complicações infecciosas após fraturas múltiplas não esclarecidas tem amparo no Código de Ética Médica.", "A não abertura de protocolo de morte encefálica em paciente com quadro compatível está justificada se o paciente for sabidamente portador de covid-19, não podendo ser potencial doador de órgãos.", "A revelação de gravidez aos pais de adolescente incapaz não fere o sigilo médico e o direito à privacidade da mesma, pelo risco de envolver potencial dano ao feto."], correctIndex: 2 },
];
